import React, { useState } from 'react';
import useStyles from './Layout/styles';
import { useTranslation } from 'react-i18next';
import LandingImageNorwegian from '../images/UllevaalStadion.png';
import LandingImageEnglish from '../images/landingImageEnglish.jpg';
import Button from '@material-ui/core/Button';

const Home = () => {
  const classes = useStyles();
  const { t, i18n } = useTranslation();
  const [selectedLanguage, setSelectedLanguage] = useState(i18n.language);

  // Update the selected language when it changes
  i18n.on('languageChanged', (lng) => {
    setSelectedLanguage(lng);
  });

  const getImageSource = () => {
    // Conditionally return the appropriate image source based on the selected language
    return selectedLanguage === 'en' ? LandingImageEnglish : LandingImageNorwegian;
  };

  return (
    <div className={classes.homeContainer}>
      {/* Main Image */}
      <img
        className={classes.heroImage}
        src={getImageSource()}
        alt="Soccer Jersey Collection"
      />

      {/* Content Section */}
      <div className={classes.contentContainer}>
        <div className={classes.contentInner}>
          {/* Welcome Text */}
          <div className={classes.welcomeText}>
            <h1>Welcome to My Soccer Collection</h1>
            <p>Explore the world of soccer jerseys and memorabilia.</p>
            {/* Read More Button */}
            <Button
              variant="outlined"
              className={classes.readMoreButton}
            >
              Read More
            </Button>
          </div>

          {/* Images to the Left */}
          <div className={classes.imagesContainer}>
            {/* Bottom Image */}
            <img
              className={classes.bottomImage}
              src="path-to-bottom-image.jpg"
              alt="Bottom Soccer Jersey"
            />
            {/* Top Image (overlapping the bottom image) */}
            <img
              className={classes.topImage}
              src="path-to-top-image.jpg"
              alt="Top Soccer Jersey"
            />
          </div>
        </div>
      </div>
    </div>
  );
};

export default Home;
